import { createTheme } from "@mui/material";

export const Theme = createTheme({
    palette:{
        primary:{
            main:"#007693"
        },
        secondary:{
            main:"#B5D4DC"
        }
    },
    components: {
        MuiButton: {
          styleOverrides: {
            root: {
              variants: [
                {
                  props: { variant: 'dashed', color: 'primary' },
                  
                },
              ],
            },
          },
        },
      },
})
